package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonSyntaxException;
import com.google.gson.internal.Primitives;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class GsonFromJsonStringClassTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void fromJson_validJson_returnsObject() throws Exception {
    String json = "{\"value\":\"test\"}";
    Class<TestClass> clazz = TestClass.class;

    // We spy gson to mock the fromJson(String, TypeToken) call
    Gson spyGson = Mockito.spy(gson);
    TestClass expectedObject = new TestClass("test");
    // Mock the call to fromJson(String, TypeToken) to return expectedObject
    doReturn(expectedObject).when(spyGson).fromJson(eq(json), any(TypeToken.class));

    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      primitivesMockedStatic.when(() -> Primitives.wrap(clazz)).thenReturn(clazz);

      TestClass actual = spyGson.fromJson(json, clazz);

      assertNotNull(actual);
      assertEquals(expectedObject.value, actual.value);
      // Verify that fromJson(String, TypeToken) was called once with correct params
      verify(spyGson, times(1)).fromJson(eq(json), any(TypeToken.class));
      primitivesMockedStatic.verify(() -> Primitives.wrap(clazz), times(1));
    }
  }

  @Test
  public void fromJson_nullJson_returnsNull() throws Exception {
    String json = null;
    Class<TestClass> clazz = TestClass.class;

    Gson spyGson = Mockito.spy(gson);
    doReturn(null).when(spyGson).fromJson(eq(json), any(TypeToken.class));

    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      primitivesMockedStatic.when(() -> Primitives.wrap(clazz)).thenReturn(clazz);

      TestClass actual = spyGson.fromJson(json, clazz);

      assertNull(actual);
      verify(spyGson, times(1)).fromJson(eq(json), any(TypeToken.class));
      primitivesMockedStatic.verify(() -> Primitives.wrap(clazz), times(1));
    }
  }

  @Test
  public void fromJson_invalidJson_throwsJsonSyntaxException() throws Exception {
    String json = "invalid json";
    Class<TestClass> clazz = TestClass.class;

    Gson spyGson = Mockito.spy(gson);
    doThrow(new JsonSyntaxException("syntax error")).when(spyGson).fromJson(eq(json), any(TypeToken.class));

    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      primitivesMockedStatic.when(() -> Primitives.wrap(clazz)).thenReturn(clazz);

      assertThrows(JsonSyntaxException.class, () -> spyGson.fromJson(json, clazz));
      verify(spyGson, times(1)).fromJson(eq(json), any(TypeToken.class));
      primitivesMockedStatic.verify(() -> Primitives.wrap(clazz), times(1));
    }
  }

  // Helper class for test
  private static class TestClass {
    String value;

    TestClass(String value) {
      this.value = value;
    }
  }
}
